#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Edge{
    int to,val;
};

struct Node{
    Node *son[2];
}*root;

void creat(Node *p){
    p->son[0]=p->son[1]=NULL;
}

int n,a[N],ans;
bool vis[N];
vector<Edge> g[N];

void bfs(int x){
    queue<int> q;
    q.push(x);
    vis[x]=1;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!vis[g[f][i].to])
                q.push(g[f][i].to),a[g[f][i].to]=a[f]^g[f][i].val,vis[g[f][i].to]=1;
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    bfs(1);
    root=new Node;
    creat(root);
    for(int i=1;i<=n;i++){
        if(i>1){
            Node *p=root;
            int sum=0;
            for(int j=30;j>=0;j--){
                if(p->son[!(a[i]&(1<<j))]!=NULL)
                    p=p->son[!(a[i]&(1<<j))],sum+=1<<j;
                else
                    p=p->son[bool(a[i]&(1<<j))];
            }
            ans=max(ans,sum);
        }
        Node *p=root;
        for(int j=30;j>=0;j--){
            if(p->son[bool(a[i]&(1<<j))]==NULL){
                Node *q=new Node;
                creat(q);
                p->son[bool(a[i]&(1<<j))]=q;
            }
            p=p->son[bool(a[i]&(1<<j))];
        }
    }
    printf("%d",ans);
    return 0;
}
